import json

# Load funding data
funding_path = 'var_functions.query_db:8'
if isinstance(funding_path, str) and funding_path.endswith('.json'):
    with open(funding_path, 'r') as f:
        funding_data = json.load(f)
else:
    funding_data = locals().get('var_functions.query_db:8', [])

# Load civic documents
civic_docs_path = 'var_functions.query_db:12'
if isinstance(civic_docs_path, str) and civic_docs_path.endswith('.json'):
    with open(civic_docs_path, 'r') as f:
        civic_docs = json.load(f)
else:
    civic_docs = locals().get('var_functions.query_db:12', [])

# Create status map from civic documents
status_map = {}

for doc in civic_docs:
    text = doc.get('text', '')
    # Simple extraction - look for common patterns
    if 'Construction was completed' in text or 'Notice of completion' in text:
        # Extract project names near these phrases
        lines = text.split('\n')
        for i, line in enumerate(lines):
            if 'Construction was completed' in line or 'Notice of completion' in line:
                # Look backwards for project name
                for j in range(i-1, max(i-5, -1), -1):
                    prev_line = lines[j].strip()
                    if prev_line and not prev_line.startswith('(') and len(prev_line) > 10:
                        if any(keyword in prev_line for keyword in ['Project', 'Improvements', 'Repairs', 'Replacement']):
                            status_map[prev_line] = 'completed'
                            break

    if 'Complete Design:' in text or 'Final Design:' in text or 'under construction' in text.lower():
        lines = text.split('\n')
        for i, line in enumerate(lines):
            if 'Complete Design:' in line or 'Final Design:' in line or 'under construction' in line.lower():
                # Look backwards for project name
                for j in range(i-1, max(i-5, -1), -1):
                    prev_line = lines[j].strip()
                    if prev_line and not prev_line.startswith('(') and len(prev_line) > 10:
                        if any(keyword in prev_line for keyword in ['Project', 'Improvements', 'Repairs', 'Replacement']):
                            status_map[prev_line] = 'design'
                            break

# Combine data
results = []
for record in funding_data:
    proj_name = record.get('Project_Name', '')
    funding_source = record.get('Funding_Source', '')
    amount = int(record.get('Amount', 0))

    status = 'not started'
    if proj_name in status_map:
        status = status_map[proj_name]
    else:
        base_name = proj_name.split('(')[0].strip()
        for known_project, known_status in status_map.items():
            if base_name in known_project or known_project in base_name:
                status = known_status
                break

    results.append({
        'Project_Name': proj_name,
        'Funding_Source': funding_source,
        'Amount': amount,
        'Status': status
    })

# Sort by project name
results.sort(key=lambda x: x['Project_Name'])

print('__RESULT__:')
print(json.dumps(results, indent=2))

